const fs = require('fs');
const data = JSON.parse(fs.readFileSync('factor_baselines.json','utf8'));
const keys = Object.keys(data);
console.log('Total entries:', keys.length);

// 待发货 entries
const df = keys.filter(k => data[k].stage === '待发货');
console.log('Entries with stage 待发货:', df.length);

let c5a=0, c5b=0;
df.forEach(k => {
  const e = data[k];
  const bl = e.baselines || {};
  const s5a = bl.S5a_A || null;
  const s5b = bl.S5b || null;
  if (s5a) c5a++;
  if (s5b) c5b++;
  console.log(e.name.padEnd(34), '| tier='+e.meta.customer_tier, '| S5a_A='+String(s5a||'null').padEnd(12), '| S5b='+String(s5b||'null').padEnd(12));
});
console.log();
console.log('待发货 with S5a_A non-null:', c5a+'/'+df.length);
console.log('待发货 with S5b non-null:  ', c5b+'/'+df.length);
