const fs = require('fs');
const data = JSON.parse(fs.readFileSync('factor_baselines.json','utf8'));
const keys = Object.keys(data);
console.log('=== Tier Distribution ===');
const tiers = {};
const addrs = {true: 0, false: 0};
const csd = {null: 0, not_null: 0};
keys.forEach(k => {
  const m = data[k].meta || {};
  const t = m.customer_tier || 'UNKNOWN';
  tiers[t] = (tiers[t] || 0) + 1;
  addrs[m.has_address === true ? 'true' : 'false']++;
  if (m.committed_ship_date === null || m.committed_ship_date === undefined) csd.null++;
  else csd.not_null++;
});
Object.entries(tiers).sort().forEach(([k,v]) => console.log('  '+k+':', v));
console.log('Sum of tiers:', Object.values(tiers).reduce((a,b)=>a+b,0));
console.log();
console.log('has_address:');
console.log('  true:', addrs.true, ', false:', addrs.false);
console.log();
console.log('committed_ship_date:');
console.log('  null:', csd.null, ', not_null:', csd.not_null);
